#include<bits/stdc++.h>
using namespace std;

int a[200005], dp[200005], ans = -2e9;

int main()
{
	int n;
	cin >> n;
	for(int i = 1; i <= n; i++)
		cin >> a[i];
    for(int i = 1; i <= n; i++)
        dp[i] = max(a[i], dp[i - 1] + a[i]);
	for(int i = 1; i <= n; i++)
        ans = max(ans, dp[i]);
	cout << ans << ' ';
	return 0;
}
